import{_ as a,c as i,o,ax as s}from"./chunks/framework.DHqKNX4U.js";const u=JSON.parse('{"title":"SMTP Journaling","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/journaling/guide.md","filePath":"enterprise/journaling/guide.md"}'),n={name:"enterprise/journaling/guide.md"};function t(r,e,l,d,h,c){return o(),i("div",null,e[0]||(e[0]=[s(`<h1 id="smtp-journaling" tabindex="-1">SMTP Journaling <a class="header-anchor" href="#smtp-journaling" aria-label="Permalink to &quot;SMTP Journaling&quot;">​</a></h1><p>SMTP Journaling allows Open Archiver to receive journal reports directly from your corporate mail transfer agent (MTA) — such as Microsoft Exchange, Microsoft 365, or Postfix — via an embedded SMTP listener. This provides a real-time, unaltered copy of every email including BCC and envelope routing data.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>When journaling is enabled, Open Archiver runs an embedded SMTP server alongside the main application. Your MTA is configured to send journal reports to a unique routing address for each journaling source. The SMTP listener validates each connection by IP whitelist, optional TLS, and optional SMTP AUTH credentials before accepting the email and queuing it for archival processing.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Open Archiver Enterprise license with the <strong>Journaling</strong> feature enabled.</li><li>A domain or subdomain with an <strong>MX record</strong> pointing to the server running Open Archiver (e.g., <code>journal.yourdomain.com</code>).</li><li>Network/firewall rules allowing inbound SMTP traffic on the configured port (default: <code>2525</code>).</li></ul><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><p>Add the following to your <code>.env</code> file:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>SMTP_JOURNALING_PORT</code></td><td><code>2525</code></td><td>The port the SMTP listener binds to inside the container. The <code>docker-compose.yml</code> maps this to the host.</td></tr><tr><td><code>SMTP_JOURNALING_DOMAIN</code></td><td><code>localhost</code></td><td>The domain used to generate routing addresses (e.g., <code>journal-abc12345@journal.yourdomain.com</code>). Set this to the domain whose MX record points to this server.</td></tr><tr><td><code>JOURNAL_QUEUE_BACKPRESSURE_THRESHOLD</code></td><td><code>10000</code></td><td>Maximum waiting jobs before the listener returns 4xx temporary failures.</td></tr></tbody></table><h2 id="docker-deployment" tabindex="-1">Docker Deployment <a class="header-anchor" href="#docker-deployment" aria-label="Permalink to &quot;Docker Deployment&quot;">​</a></h2><p>The <code>docker-compose.yml</code> exposes the SMTP port on the host:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;25:\${SMTP_JOURNALING_PORT:-2525}&#39;</span></span></code></pre></div><p>The host-side port is configurable via <code>.env</code>. The container-side port is fixed at <code>25</code>, which is the default SMTP listening port.</p><h3 id="firewall-configuration" tabindex="-1">Firewall Configuration <a class="header-anchor" href="#firewall-configuration" aria-label="Permalink to &quot;Firewall Configuration&quot;">​</a></h3><p>Ensure your server&#39;s firewall allows inbound TCP on the SMTP listening port:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># UFW example</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 25/tcp</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># iptables example</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INPUT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dport</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 25</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ACCEPT</span></span></code></pre></div><p>If using a cloud provider (AWS, GCP, Azure), add an inbound rule to your security group or firewall for TCP port <code>25</code> (or your custom port).</p><h2 id="dns-configuration" tabindex="-1">DNS Configuration <a class="header-anchor" href="#dns-configuration" aria-label="Permalink to &quot;DNS Configuration&quot;">​</a></h2><p>Create an MX record for the journaling subdomain pointing to your Open Archiver server:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>journal.yourdomain.com.  IN  MX  10  archiver.yourdomain.com.</span></span></code></pre></div><p>Where <code>archiver.yourdomain.com</code> resolves to the IP address of your Open Archiver server.</p><h2 id="creating-a-journaling-source" tabindex="-1">Creating a Journaling Source <a class="header-anchor" href="#creating-a-journaling-source" aria-label="Permalink to &quot;Creating a Journaling Source&quot;">​</a></h2><ol><li>Navigate to <strong>Dashboard → Ingestions → Journaling</strong> in the Open Archiver UI.</li><li>Click <strong>Create Journaling Source</strong>.</li><li>Configure: <ul><li><strong>Name</strong>: A descriptive name (e.g., &quot;Exchange Production&quot;).</li><li><strong>Allowed IPs</strong>: The IP addresses or CIDR blocks of your MTA servers (e.g., <code>10.0.0.0/8</code>, <code>203.0.113.50</code>).</li><li><strong>Require TLS</strong>: Enable if your MTA supports STARTTLS (recommended for GDPR compliance).</li><li><strong>Organization Domains</strong> (optional): Define domain groups to correctly identify which inbox each journaled email belongs to. See <a href="#organization-domain-groups">Organization Domain Groups</a> for details.</li><li><strong>SMTP Username / Password</strong> (optional): If set, the sending MTA must authenticate with these credentials before delivering journal reports. If the sender does not authenticate, the email is rejected.</li></ul></li><li>After creation, the UI displays a <strong>Routing Address</strong> (e.g., <code>journal-abc12345@journal.yourdomain.com</code>). Configure this address as the journal recipient in your MTA.</li></ol><h2 id="editing-a-journaling-source" tabindex="-1">Editing a Journaling Source <a class="header-anchor" href="#editing-a-journaling-source" aria-label="Permalink to &quot;Editing a Journaling Source&quot;">​</a></h2><p>When editing a source that has an SMTP password configured:</p><ul><li>The password field is always empty when the edit form opens (the existing password is stored as a bcrypt hash and cannot be retrieved).</li><li>If a password is currently set, the form shows a hint: <strong>&quot;A password is currently set. Leave this field blank to keep it, or type a new password to replace it.&quot;</strong></li><li>To <strong>keep the existing password</strong>: leave the password field blank and save.</li><li>To <strong>change the password</strong>: type the new password and save.</li><li>To <strong>remove password authentication entirely</strong>: clear the username field and leave the password field blank, then save. Both fields being empty disables SMTP AUTH for that source.</li></ul><hr><h2 id="organization-domain-groups" tabindex="-1">Organization Domain Groups <a class="header-anchor" href="#organization-domain-groups" aria-label="Permalink to &quot;Organization Domain Groups&quot;">​</a></h2><p>Organization Domain Groups tell Open Archiver which email addresses belong to your organization. This is used to determine <strong>which inbox (<code>userEmail</code>) a journaled email is filed under</strong> — a value that drives IAM access control (who can search which emails) and Meilisearch scoping.</p><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>A journal report received via SMTP contains all participants: To, CC, BCC, and From. Open Archiver must decide which of those addresses is the &quot;owner&quot; — the internal inbox the email belongs to. Without domain configuration, it uses a simple heuristic (first To address). With domain groups configured, it correctly identifies internal recipients even when your organization uses multiple domains or has migrated from an old domain.</p><h3 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">​</a></h3><p>Each domain group has:</p><ul><li><strong>Primary domain</strong> (<code>main</code>): The canonical domain used for storage and search. All email addresses from alias domains are normalized to this domain before being stored.</li><li><strong>Alias domains</strong> (<code>aliases</code>): Zero or more additional domains that belong to the same organization. Addresses at these domains are treated identically to the primary domain.</li></ul><p><strong>Example configuration:</strong></p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">		&quot;main&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;company.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">		&quot;aliases&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;company.co.uk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;old-brand.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">		&quot;main&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;subsidiary.io&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">		&quot;aliases&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>Multiple groups are supported — useful when your Open Archiver instance archives emails for multiple organizations or subsidiaries.</p><h3 id="how-owner-resolution-works" tabindex="-1">How Owner Resolution Works <a class="header-anchor" href="#how-owner-resolution-works" aria-label="Permalink to &quot;How Owner Resolution Works&quot;">​</a></h3><p>For each inbound journaled email, Open Archiver resolves the owner address using the following priority order:</p><ol><li><p><strong>Inbound check (To / CC / BCC)</strong>: Scan all recipient addresses in order (To first, then CC, then BCC). The first recipient whose domain matches any configured domain (either <code>main</code> or an <code>alias</code>) is selected as the owner.</p></li><li><p><strong>Outbound check (From)</strong>: If no recipient matched, check whether the sender&#39;s domain matches a configured domain. If so, the email is outgoing from an internal mailbox and the sender is the owner.</p></li><li><p><strong>Fallback (no groups configured)</strong>: If no domain groups are configured at all, a simple heuristic is used: <code>To[0] → CC[0] → BCC[0] → From[0] → &#39;journal-unknown&#39;</code>.</p></li><li><p><strong>No match with groups configured</strong>: If domain groups exist but no participant matched any of them (e.g., a forwarded external email with no internal participants), the address is set to <code>default_fallback@&lt;primary domain of first group&gt;</code> and a warning is logged.</p></li></ol><h3 id="domain-normalization-alias-handling" tabindex="-1">Domain Normalization (Alias Handling) <a class="header-anchor" href="#domain-normalization-alias-handling" aria-label="Permalink to &quot;Domain Normalization (Alias Handling)&quot;">​</a></h3><p>When an owner is matched via an alias domain, the address is automatically normalized to the primary domain before being stored. This ensures that emails sent to <code>user@old-brand.com</code> and emails sent to <code>user@company.com</code> are stored under the same mailbox identity.</p><p><strong>Example:</strong></p><table tabindex="0"><thead><tr><th>Journaled email recipient</th><th>Configured group</th><th>Stored <code>userEmail</code></th></tr></thead><tbody><tr><td><code>alice@old-brand.com</code></td><td><code>{ main: &quot;company.com&quot;, aliases: [&quot;old-brand.com&quot;] }</code></td><td><code>alice@company.com</code></td></tr><tr><td><code>alice@company.com</code></td><td><code>{ main: &quot;company.com&quot;, aliases: [&quot;old-brand.com&quot;] }</code></td><td><code>alice@company.com</code></td></tr><tr><td><code>bob@subsidiary.io</code></td><td><code>{ main: &quot;subsidiary.io&quot;, aliases: [] }</code></td><td><code>bob@subsidiary.io</code></td></tr><tr><td><code>external@gmail.com</code></td><td><em>(no match)</em></td><td><code>default_fallback@company.com</code></td></tr></tbody></table><h3 id="practical-scenarios" tabindex="-1">Practical Scenarios <a class="header-anchor" href="#practical-scenarios" aria-label="Permalink to &quot;Practical Scenarios&quot;">​</a></h3><p><strong>Single domain, no migration:</strong> Leave Organization Domains empty. The system uses the heuristic <code>To[0]</code> address. This works correctly for most single-domain setups.</p><p><strong>Domain migration or rebrand:</strong> Your company moved from <code>old-brand.com</code> to <code>company.com</code>. Configure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main: company.com</span></span>
<span class="line"><span>aliases: old-brand.com</span></span></code></pre></div><p>Emails addressed to either domain are now filed under <code>company.com</code> addresses, giving users a unified view of their archive regardless of when the email was sent.</p><p><strong>Multiple alias domains (e.g., regional TLDs):</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main: company.com</span></span>
<span class="line"><span>aliases: company.co.uk, company.de, company.fr</span></span></code></pre></div><p><strong>Multiple subsidiaries, one Open Archiver instance:</strong> Create two groups:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Group 1: main: parent.com,      aliases: []</span></span>
<span class="line"><span>Group 2: main: subsidiary.io,   aliases: [sub-old.com]</span></span></code></pre></div><hr><h2 id="mta-configuration-examples" tabindex="-1">MTA Configuration Examples <a class="header-anchor" href="#mta-configuration-examples" aria-label="Permalink to &quot;MTA Configuration Examples&quot;">​</a></h2><h3 id="google-workspace" tabindex="-1">Google Workspace <a class="header-anchor" href="#google-workspace" aria-label="Permalink to &quot;Google Workspace&quot;">​</a></h3><p>Google Workspace does not have a native journaling feature like Exchange. Instead, use a <strong>Routing</strong> rule to deliver a copy of all email to the Open Archiver journaling address:</p><ol><li>In the Google Admin Console, go to <strong>Apps → Google Workspace → Gmail → Routing</strong>.</li><li>Under <strong>Routing</strong>, click <strong>Configure</strong> (or <strong>Add another rule</strong>).</li><li>Configure the rule: <ul><li><strong>Name</strong>: &quot;Journal to Open Archiver&quot;</li><li><strong>Email messages to affect</strong>: Select <strong>Inbound</strong>, <strong>Outbound</strong>, and <strong>Internal - sending</strong> as needed.</li><li>Under <strong>For the above types of messages, do the following</strong>, select <strong>Modify message</strong>.</li><li>Check <strong>Also deliver to</strong> → <strong>Add more recipients</strong> → enter the routing address from Open Archiver (e.g., <code>journal-abc12345@journal.yourdomain.com</code>).</li><li>For the added recipient, click <strong>Advanced settings</strong> → <strong>Change route</strong> and configure the SMTP route to point to <code>archiver.yourdomain.com</code> on port <code>2525</code>. Enable <strong>Require TLS</strong> if your journaling source has TLS enabled.</li><li>Optionally check <strong>Do not deliver spam to this recipient</strong> to avoid archiving spam.</li></ul></li><li>Click <strong>Save</strong>.</li></ol><blockquote><p><strong>Note</strong>: Changes to Gmail routing rules may take up to 24 hours to propagate across all users. For the allowed IPs in your journaling source, use Google&#39;s SMTP relay IP ranges (see <a href="https://support.google.com/a/answer/60764" target="_blank" rel="noreferrer">Google IP ranges</a>).</p></blockquote><h3 id="microsoft-365-exchange-online" tabindex="-1">Microsoft 365 / Exchange Online <a class="header-anchor" href="#microsoft-365-exchange-online" aria-label="Permalink to &quot;Microsoft 365 / Exchange Online&quot;">​</a></h3><ol><li>In the Exchange Admin Center, go to <strong>Compliance Management → Journal Rules</strong>.</li><li>Create a new journal rule: <ul><li><strong>Send journal reports to</strong>: The routing address from Open Archiver (e.g., <code>journal-abc12345@journal.yourdomain.com</code>).</li><li><strong>Scope</strong>: Select &quot;All messages&quot; or scope to specific users/groups.</li></ul></li><li>Ensure your Exchange connector allows outbound SMTP to the Open Archiver server on port <code>2525</code>.</li></ol><h3 id="on-premises-exchange" tabindex="-1">On-Premises Exchange <a class="header-anchor" href="#on-premises-exchange" aria-label="Permalink to &quot;On-Premises Exchange&quot;">​</a></h3><ol><li>Open the Exchange Management Shell.</li><li>Create a journal rule:<div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">New-JournalRule</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Name </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Open Archiver&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">JournalEmailAddress </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;journal-abc12345@journal.yourdomain.com&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope Global </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Enabled </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$true</span></span></code></pre></div></li><li>Create a Send Connector for the journaling subdomain pointing to the Open Archiver server&#39;s IP and port.</li></ol><h3 id="postfix" tabindex="-1">Postfix <a class="header-anchor" href="#postfix" aria-label="Permalink to &quot;Postfix&quot;">​</a></h3><p>Add a transport map entry to route journal emails to the Open Archiver SMTP listener:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># /etc/postfix/transport</span></span>
<span class="line"><span>journal.yourdomain.com    smtp:[archiver.yourdomain.com]:2525</span></span></code></pre></div><p>Then run <code>postmap /etc/postfix/transport</code> and reload Postfix.</p><hr><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><p>Each journaling source can optionally require SMTP AUTH (username + password). When credentials are configured on a source, the sending MTA <strong>must</strong> authenticate before delivering email. Unauthenticated connections are rejected at the RCPT TO stage.</p><p>Sources without credentials configured rely solely on IP whitelisting for access control.</p><p>Passwords are stored as bcrypt hashes in the database and are never returned by the API. When editing a source in the UI, the password field is always empty — see <a href="#editing-a-journaling-source">Editing a Journaling Source</a> for instructions on changing or clearing a password.</p><h3 id="ip-whitelisting" tabindex="-1">IP Whitelisting <a class="header-anchor" href="#ip-whitelisting" aria-label="Permalink to &quot;IP Whitelisting&quot;">​</a></h3><p>Every connection is validated against the IP whitelist in two stages:</p><ol><li><strong>onConnect</strong>: Rejects IPs not whitelisted by <em>any</em> active source (early filter).</li><li><strong>onRcptTo</strong>: After resolving the specific source by routing address, validates the IP against <em>that source&#39;s</em> whitelist.</li></ol><h3 id="tls" tabindex="-1">TLS <a class="header-anchor" href="#tls" aria-label="Permalink to &quot;TLS&quot;">​</a></h3><p>When <code>requireTls</code> is enabled on a source, connections without TLS (STARTTLS) are rejected. This is recommended for compliance with GDPR and other data protection regulations.</p><hr><h2 id="health-check" tabindex="-1">Health Check <a class="header-anchor" href="#health-check" aria-label="Permalink to &quot;Health Check&quot;">​</a></h2><p>The SMTP listener exposes a health endpoint:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /v1/enterprise/journaling/health</span></span></code></pre></div><p>Returns <code>200</code> with <code>{ &quot;smtp&quot;: &quot;listening&quot;, &quot;port&quot;: &quot;2525&quot; }</code> when healthy, or <code>503</code> when the listener is down.</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="smtp-listener-not-starting" tabindex="-1">SMTP listener not starting <a class="header-anchor" href="#smtp-listener-not-starting" aria-label="Permalink to &quot;SMTP listener not starting&quot;">​</a></h3><p>Check the application logs for errors like &quot;Failed to start SMTP journaling listener&quot;. Common causes:</p><ul><li>Port already in use by another process.</li><li>Missing database migration (the <code>journaling_sources</code> table must exist).</li><li>The Journaling feature is not enabled in the license.</li></ul><h3 id="emails-not-being-received" tabindex="-1">Emails not being received <a class="header-anchor" href="#emails-not-being-received" aria-label="Permalink to &quot;Emails not being received&quot;">​</a></h3><ol><li>Verify the MX record resolves correctly: <code>dig MX journal.yourdomain.com</code></li><li>Verify the port is reachable: <code>telnet archiver.yourdomain.com 2525</code></li><li>Check the allowed IPs on the journaling source match the MTA&#39;s outbound IP.</li><li>If SMTP AUTH is configured, ensure the MTA is sending credentials.</li><li>Check application logs for rejection messages (IP not whitelisted, TLS required, authentication required).</li></ol><h3 id="emails-filed-under-wrong-mailbox" tabindex="-1">Emails filed under wrong mailbox <a class="header-anchor" href="#emails-filed-under-wrong-mailbox" aria-label="Permalink to &quot;Emails filed under wrong mailbox&quot;">​</a></h3><p>If archived emails are appearing under unexpected mailbox addresses (e.g., <code>default_fallback@company.com</code> or an external sender&#39;s address), the <strong>Organization Domains</strong> configuration may be missing or incomplete.</p><ol><li>Edit the journaling source and add Organization Domain Groups covering your company&#39;s domains.</li><li>If you have alias or legacy domains, add them as aliases under the correct primary domain.</li><li>New emails received after saving will use the updated configuration. Previously archived emails are not retroactively re-filed.</li></ol><h3 id="queue-backpressure-4xx-errors" tabindex="-1">Queue backpressure (4xx errors) <a class="header-anchor" href="#queue-backpressure-4xx-errors" aria-label="Permalink to &quot;Queue backpressure (4xx errors)&quot;">​</a></h3><p>If the MTA receives temporary 4xx failures, the journal-inbound queue has exceeded the backpressure threshold. This means workers can&#39;t keep up with inbound volume. Solutions:</p><ul><li>Increase <code>JOURNAL_QUEUE_BACKPRESSURE_THRESHOLD</code> if the server has capacity.</li><li>Scale up the journaling worker processes.</li><li>Check for processing errors in the worker logs.</li></ul>`,96)]))}const g=a(n,[["render",t]]);export{u as __pageData,g as default};
